svg.script:
const TIPS = {
  hs1: {
    title: '① Core — positive void coefficient',
    lines: [
      'When cooling water flashed to steam, void fraction rose.',
      'Instead of shutting down (negative void = safe), RBMK',
      'added reactivity — up to +5β_eff on full steaming.',
      'Once ρ > β the core became prompt supercritical:',
      'power grew on μs timescale, not the slower delayed-n scale.'
    ]
  },
  hs2: {
    title: '② Control rods — withdrawn (ORM = 8)',
    lines: [
      '201 of 211 absorber rods were effectively out of the core.',
      'Operating rules required ≥15 rods (hard minimum).',
      'Below 50% power the procedure table required ≥30 rods.',
      'Operators did not appreciate the physical danger of ORM < 15;',
      'they were told ORM was an "efficiency" limit, not a safety one.'
    ]
  },
  hs3: {
    title: '③ Graphite-tipped rods — positive scram effect',
    lines: [
      'Each rod had a 1.25 m water gap above its graphite follower.',
      'On insertion, graphite entered the lower core first,',
      'replacing neutron-absorbing water with a moderator.',
      'This gave an initial burst of positive reactivity (~+1β)',
      'before absorption finally caught up — too late at 200 MW(th).'
    ]
  },
  hs4: {
    title: '④ Upper shield plate — 1000-tonne cover',
    lines: [
      'Steam-dump system was rated for only 2 channel ruptures.',
      'Multi-channel failure pressurised the reactor cavity.',
      'Overpressure lifted the 1000 t upper biological shield,',
      'jamming control rods at mid-insertion.',
      'Two explosions followed: steam-driven, then H₂/Zr detonation.'
    ]
  }
};

const tt      = document.getElementById('tt');
const ttBg    = document.getElementById('tt-bg');
const ttTitle = document.getElementById('tt-title');
const ttBody  = document.getElementById('tt-body');

function showTip(id, evt) {
  const tip = TIPS[id];
  if (!tip) return;
  ttTitle.textContent = tip.title;
  while (ttBody.firstChild) ttBody.removeChild(ttBody.firstChild);
  tip.lines.forEach((line, i) => {
    const t = document.createElementNS('http://www.w3.org/2000/svg', 'tspan');
    t.setAttribute('x', '12');
    t.setAttribute('dy', i === 0 ? '0' : '13');
    t.textContent = line;
    ttBody.appendChild(t);
  });
  const h = 28 + tip.lines.length * 13 + 8;
  ttBg.setAttribute('height', h);
  document.querySelector('#tt rect:nth-child(2)').setAttribute('height', h);
  const svg   = tt.ownerSVGElement;
  const pt    = svg.createSVGPoint();
  pt.x = evt.clientX; pt.y = evt.clientY;
  const svgPt = pt.matrixTransform(svg.getScreenCTM().inverse());
  let tx = svgPt.x + 16;
  let ty = svgPt.y - 16;
  if (tx + 340 > 1080) tx = svgPt.x - 350;
  if (ty < 0) ty = 4;
  tt.setAttribute('transform', 'translate(' + tx + ',' + ty + ')');
  tt.style.display = 'block';
}

['hs1','hs2','hs3','hs4'].forEach(id => {
  const el = document.getElementById(id);
  if (!el) return;
  el.addEventListener('mouseenter', e => showTip(id, e));
  el.addEventListener('mousemove',  e => showTip(id, e));
  el.addEventListener('mouseleave', () => { tt.style.display = 'none'; });
});
